class FASTDecoder:
    def __init__(self):
        self.previous_values = {}

    def encode_stop_bit(self, value: int) -> list:
        if value == 0:
            return [0x80]  # single byte: stop bit + zero data

        groups = []
        v = value
        while v > 0:
            groups.append(v & 0x7F)
            v >>= 7

        groups.reverse()
        # Set stop bit on last byte
        result = []
        for i, g in enumerate(groups):
            if i == len(groups) - 1:
                result.append(g | 0x80)  # set MSB (stop bit)
            else:
                result.append(g)  # MSB clear (more follows)
        return result

    def decode_stop_bit(self, data: list, offset: int) -> tuple:
        value = 0
        pos = offset
        while pos < len(data):
            byte = data[pos]
            value = (value << 7) | (byte & 0x7F)
            pos += 1
            if byte & 0x80:  # stop bit set
                break
        return (value, pos)

    def decode_signed_stop_bit(self, data: list, offset: int) -> tuple:
        value = 0
        pos = offset
        is_first = True
        sign_negative = False
        num_bits = 0

        while pos < len(data):
            byte = data[pos]
            data_bits = byte & 0x7F

            if is_first:
                sign_negative = bool(data_bits & 0x40)  # bit 6 of first byte
                if sign_negative:
                    value = -1  # start with all 1s for sign extension
                value = (value << 7) | data_bits
                is_first = False
            else:
                value = (value << 7) | data_bits

            num_bits += 7
            pos += 1
            if byte & 0x80:
                break

        return (value, pos)

    def decode_pmap(self, data: list, offset: int) -> tuple:
        bits = []
        pos = offset
        while pos < len(data):
            byte = data[pos]
            for i in range(6, -1, -1):
                bits.append((byte >> i) & 1)
            pos += 1
            if byte & 0x80:
                break
        return (bits, pos)

    def decode_string(self, data: list, offset: int) -> tuple:
        chars = []
        pos = offset

        # Check for NULL string
        if pos < len(data) and data[pos] == 0x80:
            return ('', pos + 1)

        while pos < len(data):
            byte = data[pos]
            if byte & 0x80:
                chars.append(chr(byte & 0x7F))
                pos += 1
                break
            else:
                chars.append(chr(byte))
                pos += 1
        return (''.join(chars), pos)

    def decode_message(self, data: list, template: list) -> dict:
        result = {}
        pmap, offset = self.decode_pmap(data, 0)
        pmap_idx = 0

        for field in template:
            name = field['name']
            ftype = field['type']
            optional = field.get('optional', False)
            operator = field.get('operator', 'none')
            default_val = field.get('value', None)

            # Determine if field is present based on operator and pmap
            if operator == 'constant':
                result[name] = default_val
                continue

            has_pmap_bit = operator in ('copy', 'default', 'increment') or optional

            if has_pmap_bit:
                pbit = pmap[pmap_idx] if pmap_idx < len(pmap) else 0
                pmap_idx += 1
            else:
                pbit = 1  # always present for 'none' operator

            if pbit == 0:
                # Use previous/default value
                if operator == 'copy':
                    result[name] = self.previous_values.get(name, default_val)
                elif operator == 'default':
                    result[name] = default_val
                elif operator == 'increment':
                    prev = self.previous_values.get(name, 0)
                    result[name] = prev + 1
                    self.previous_values[name] = result[name]
                elif optional:
                    result[name] = None
                continue

            # Decode from wire
            if ftype == 'uint32':
                val, offset = self.decode_stop_bit(data, offset)
                if operator == 'delta':
                    prev = self.previous_values.get(name, 0)
                    val = prev + val
            elif ftype == 'int32':
                val, offset = self.decode_signed_stop_bit(data, offset)
                if operator == 'delta':
                    prev = self.previous_values.get(name, 0)
                    val = prev + val
            elif ftype == 'string':
                val, offset = self.decode_string(data, offset)
            else:
                val = None

            result[name] = val
            self.previous_values[name] = val

        return result

