class HardwareOrderBook:
    def __init__(self, base_price_int: int, num_levels: int = 1024, tick_size_int: int = 100):
        self.base = base_price_int
        self.num_levels = num_levels
        self.tick = tick_size_int
        self.bid_qty = [0] * num_levels
        self.ask_qty = [0] * num_levels
        self.bid_count = [0] * num_levels
        self.ask_count = [0] * num_levels
        self._best_bid_idx = -1
        self._best_ask_idx = num_levels
        self.total_trades = 0
        self.total_trade_volume = 0

    def _idx(self, price_int: int) -> int:
        return (price_int - self.base) // self.tick

    def _price(self, idx: int) -> int:
        return self.base + idx * self.tick

    def add_order(self, side: str, price_int: int, qty: int):
        idx = self._idx(price_int)
        if idx < 0 or idx >= self.num_levels:
            return
        if side == 'B':
            self.bid_qty[idx] += qty
            self.bid_count[idx] += 1
            if idx > self._best_bid_idx:
                self._best_bid_idx = idx
        else:
            self.ask_qty[idx] += qty
            self.ask_count[idx] += 1
            if idx < self._best_ask_idx:
                self._best_ask_idx = idx

    def cancel_order(self, side: str, price_int: int, qty: int):
        idx = self._idx(price_int)
        if idx < 0 or idx >= self.num_levels:
            return
        if side == 'B':
            self.bid_qty[idx] = max(0, self.bid_qty[idx] - qty)
            if self.bid_qty[idx] > 0:
                pass
            else:
                self.bid_count[idx] = 0
            if self.bid_qty[idx] == 0 and idx == self._best_bid_idx:
                while self._best_bid_idx >= 0 and self.bid_qty[self._best_bid_idx] == 0:
                    self._best_bid_idx -= 1
        else:
            self.ask_qty[idx] = max(0, self.ask_qty[idx] - qty)
            if self.ask_qty[idx] > 0:
                pass
            else:
                self.ask_count[idx] = 0
            if self.ask_qty[idx] == 0 and idx == self._best_ask_idx:
                while self._best_ask_idx < self.num_levels and self.ask_qty[self._best_ask_idx] == 0:
                    self._best_ask_idx += 1

    def execute_order(self, side: str, price_int: int, qty: int):
        self.total_trades += 1
        self.total_trade_volume += qty
        self.cancel_order(side, price_int, qty)

    def modify_order(self, side: str, old_price: int, new_price: int,
                     old_qty: int, new_qty: int):
        self.cancel_order(side, old_price, old_qty)
        self.add_order(side, new_price, new_qty)

    @property
    def best_bid(self) -> int:
        if self._best_bid_idx < 0:
            return 0
        return self._price(self._best_bid_idx)

    @property
    def best_ask(self) -> int:
        if self._best_ask_idx >= self.num_levels:
            return 0
        return self._price(self._best_ask_idx)

    @property
    def mid_price(self) -> int:
        bb = self.best_bid
        ba = self.best_ask
        if bb == 0 or ba == 0:
            return bb if ba == 0 else ba
        return (bb + ba) >> 1

    @property
    def spread(self) -> int:
        bb = self.best_bid
        ba = self.best_ask
        if bb == 0 or ba == 0:
            return 0
        return ba - bb

    @property
    def bid_depth(self) -> int:
        total = 0
        for q in self.bid_qty:
            total += q
        return total

    @property
    def ask_depth(self) -> int:
        total = 0
        for q in self.ask_qty:
            total += q
        return total

    @property
    def num_bid_levels(self) -> int:
        count = 0
        for q in self.bid_qty:
            if q > 0:
                count += 1
        return count

    @property
    def num_ask_levels(self) -> int:
        count = 0
        for q in self.ask_qty:
            if q > 0:
                count += 1
        return count

    def vwap(self, side: str, depth: int) -> int:
        pq_sum = 0
        q_sum = 0
        levels_counted = 0

        if side == 'B':
            idx = self._best_bid_idx
            while idx >= 0 and levels_counted < depth:
                if self.bid_qty[idx] > 0:
                    price = self._price(idx)
                    pq_sum += price * self.bid_qty[idx]
                    q_sum += self.bid_qty[idx]
                    levels_counted += 1
                idx -= 1
        else:
            idx = self._best_ask_idx
            while idx < self.num_levels and levels_counted < depth:
                if self.ask_qty[idx] > 0:
                    price = self._price(idx)
                    pq_sum += price * self.ask_qty[idx]
                    q_sum += self.ask_qty[idx]
                    levels_counted += 1
                idx += 1

        if q_sum == 0:
            return 0
        return pq_sum // q_sum  # integer division

    def get_quote(self, position: int, base_half_spread: int,
                  skew_coeff: int) -> tuple:
        mid = self.mid_price
        skew_amount = skew_coeff * position
        bid = mid - base_half_spread - skew_amount
        ask = mid + base_half_spread + skew_amount
        return (bid, ask)

class LatencyAnalyzer:
    PUBLISHED_RESULTS = [
        ('Boutros et al. 2017 (HLS)', 270),
        ('IEEE 2022 (Custom RTL)', 433),
        ('IEEE 2024 (FPGA accel)', 480),
        ('Software (kernel bypass)', 2000),
    ]

    def __init__(self, clock_freq_mhz: int = 200):
        self.clock_freq_mhz = clock_freq_mhz
        self.clock_period_ns = 1000 // clock_freq_mhz
        self.stages = []

    def add_stage(self, name: str, latency_cycles: int):
        self.stages.append((name, latency_cycles))

    def analyze_single(self) -> dict:
        stage_details = []
        total_cycles = 0
        for name, cycles in self.stages:
            ns = cycles * self.clock_period_ns
            stage_details.append({
                'name': name,
                'cycles': cycles,
                'ns': ns
            })
            total_cycles += cycles

        return {
            'stages': stage_details,
            'total_cycles': total_cycles,
            'total_ns': total_cycles * self.clock_period_ns,
            'clock_freq_mhz': self.clock_freq_mhz
        }

    def analyze_pipeline(self, num_packets: int) -> dict:
        if not self.stages:
            return {'throughput_mpps': 0, 'bottleneck_stage': '',
                    'latency_ns': 0, 'total_time_ns': 0}

        bottleneck_name, bottleneck_cycles = max(self.stages, key=lambda x: x[1])
        total_cycles = sum(c for _, c in self.stages)
        latency_ns = total_cycles * self.clock_period_ns

        # Pipeline: first packet takes full latency,
        # subsequent packets emerge every bottleneck_cycles
        pipeline_total_cycles = total_cycles + bottleneck_cycles * (num_packets - 1)
        total_time_ns = pipeline_total_cycles * self.clock_period_ns

        throughput_pps = num_packets / (total_time_ns * 1e-9) if total_time_ns > 0 else 0
        throughput_mpps = throughput_pps / 1e6

        return {
            'throughput_mpps': throughput_mpps,
            'bottleneck_stage': bottleneck_name,
            'latency_ns': latency_ns,
            'total_time_ns': total_time_ns
        }

    def find_bottleneck(self) -> tuple:
        if not self.stages:
            return ('', 0, 0)
        name, cycles = max(self.stages, key=lambda x: x[1])
        return (name, cycles, cycles * self.clock_period_ns)

    def compare_published(self) -> list:
        result = self.analyze_single()
        my_ns = result['total_ns']
        comparisons = []
        for paper, pub_ns in self.PUBLISHED_RESULTS:
            ratio = my_ns / pub_ns if pub_ns > 0 else 0
            comparisons.append((paper, pub_ns, my_ns, round(ratio, 2)))
        return comparisons

    def optimize_stage(self, name: str, new_latency_cycles: int) -> dict:
        before = self.analyze_single()

        old_cycles = 0
        for i, (n, c) in enumerate(self.stages):
            if n == name:
                old_cycles = c
                self.stages[i] = (n, new_latency_cycles)
                break

        after = self.analyze_single()

        return {
            'stage': name,
            'before_cycles': old_cycles,
            'after_cycles': new_latency_cycles,
            'before_total_ns': before['total_ns'],
            'after_total_ns': after['total_ns'],
            'improvement_ns': before['total_ns'] - after['total_ns'],
            'improvement_pct': round((before['total_ns'] - after['total_ns']) / before['total_ns'] * 100, 1) if before['total_ns'] > 0 else 0
        }
